6	//! `dialect-mir` → LLVM dialect function lowering via `inline_region`.
7	//!
8	//! This module implements [`convert_func`] — the entry point for lowering
9	//! `MirFuncOp` → `llvm.func` using pliron's `DialectConversion` framework.
10	//!
11	//! # Conversion Strategy
12	//!
13	//! 1. Creates an LLVM function with a converted (flattened) type signature
14	//! 2. Propagates GPU kernel attributes (`gpu_kernel`, cluster dims, launch bounds)
15	//! 3. Pre-scans for maximum dynamic shared memory alignment
16	//! 4. Uses `inline_region` to move MIR blocks into the LLVM function
17	//! 5. Reconstructs aggregate types (slices, structs) in an entry prologue
18	//! 6. Branches to the original MIR entry block with reconstructed values
19	//!
20	//! # Entry Block Prologue
21	//!
22	//! ```text
23	//! LLVM entry block (flattened args: ptr, len, field0, field1, ...):
24	//!   %undef_slice = llvm.mlir.undef : {ptr, i64}
25	//!   %with_ptr    = llvm.insertvalue %ptr into %undef_slice[0]
26	//!   %slice       = llvm.insertvalue %len into %with_ptr[1]
27	//!   llvm.br ^mir_entry(%slice, %field0, %field1, ...)
28	//! ```
29	
30	use crate::context::{DynamicSmemAlignmentMap, SharedGlobalsMap};
31	use crate::convert::types::{
32	    StructLayoutInfo, build_struct_slot_map, convert_function_type, convert_type, is_kernel_func,
33	    is_zero_sized_type,
34	};
35	
36	use dialect_mir::ops::MirFuncOp;
37	use dialect_mir::types::{
38	    MirDisjointSliceType, MirPtrType, MirSliceType, MirStructType, MirUnionType,
39	};
40	use llvm_export::ops as llvm;
41	use pliron::{
42	    basic_block::BasicBlock,
43	    builtin::op_interfaces::SymbolOpInterface,
44	    context::{Context, Ptr},
45	    irbuild::{
46	        dialect_conversion::{DialectConversionRewriter, OperandsInfo},
47	        inserter::{BlockInsertionPoint, Inserter, OpInsertionPoint},
48	        rewriter::Rewriter,
49	    },
50	    linked_list::ContainsLinkedList,
51	    op::Op,
52	    operation::Operation,
53	    result::Result,
54	    r#type::{TypeHandle, Typed},
55	    value::Value,
56	};
57	use rustc_hash::{FxHashMap, FxHashSet};
58	
59	const DYNAMIC_SHARED_ALIGNMENT_ATTR: &str = "dynamic_shared_alignment";
60	
61	// ============================================================================
62	// Dynamic shared-memory contract propagation
63	// ============================================================================
64	
65	/// Propagate dynamic shared-memory alignment markers through the local MIR
66	/// call graph before any function is lowered.
67	///
68	/// The marker normally belongs to a kernel entry. Attribute expansion may put
69	/// it in a generic helper when `#[launch_contract]` appears above `#[kernel]`,
70	/// so every marked local function is a propagation root. A dynamic
71	/// shared-memory access can also live in a deeper ordinary helper. Shared
72	/// helpers receive the maximum requirement from every marked root that can
73	/// reach them.
74	pub(crate) fn propagate_kernel_dynamic_shared_alignments(
75	    ctx: &mut Context,
76	    module_op: Ptr<Operation>,
77	) {
78	    let mut functions = FxHashMap::default();
79	    for region in module_op.deref(ctx).regions() {
80	        for block in region.deref(ctx).iter(ctx) {
81	            for op in block.deref(ctx).iter(ctx) {
82	                if let Some(function) = MirFuncOp::wrap(ctx, op) {
83	                    functions.insert(function.get_symbol_name(ctx).to_string(), op);
84	                }
85	            }
86	        }
87	    }
88	
89	    let call_graph: FxHashMap<String, Vec<String>> = functions
90	        .iter()
91	        .map(|(name, op)| (name.clone(), collect_mir_callees(ctx, *op)))
92	        .collect();
93	    let alignment_roots: Vec<(String, u64)> = functions
94	        .iter()
95	        .filter_map(|(name, op)| {
96	            dynamic_shared_alignment_attr(ctx, *op).map(|value| (name.clone(), value))
97	        })
98	        .collect();
99	
100	    for (name, propagated_alignment) in
101	        propagate_alignments_through_call_graph(&call_graph, &alignment_roots)
102	    {
103	        let Some(function) = functions.get(&name).copied() else {
104	            continue;
105	        };
106	        let alignment = dynamic_shared_alignment_attr(ctx, function)
107	            .map_or(propagated_alignment, |local| {
108	                local.max(propagated_alignment)
109	            });
110	        set_dynamic_shared_alignment_attr(ctx, function, alignment);
111	    }
112	}
113	
114	fn collect_mir_callees(ctx: &Context, root: Ptr<Operation>) -> Vec<String> {
115	    fn visit(ctx: &Context, op: Ptr<Operation>, callees: &mut Vec<String>) {
116	        if let Some(call) = Operation::get_op::<dialect_mir::ops::MirCallOp>(op, ctx)
117	            && let Some(callee) = call.get_attr_callee(ctx)
118	        {
119	            callees.push(String::from((*callee).clone()));
120	        }
121	
122	        let children: Vec<_> = op
123	            .deref(ctx)
124	            .regions()
125	            .flat_map(|region| region.deref(ctx).iter(ctx))
126	            .flat_map(|block| block.deref(ctx).iter(ctx))
127	            .collect();
128	        for child in children {
129	            visit(ctx, child, callees);
130	        }
131	    }
132	
133	    let mut callees = Vec::new();
134	    visit(ctx, root, &mut callees);
135	    callees.sort_unstable();
136	    callees.dedup();
137	    callees
138	}
139	
140	fn propagate_alignments_through_call_graph(
141	    call_graph: &FxHashMap<String, Vec<String>>,
142	    alignment_roots: &[(String, u64)],
143	) -> FxHashMap<String, u64> {
144	    let mut propagated = FxHashMap::default();
145	
146	    for (root, alignment) in alignment_roots {
147	        let mut worklist = vec![root.clone()];
148	        let mut visited = FxHashSet::default();
149	
150	        while let Some(function) = worklist.pop() {
151	            if !visited.insert(function.clone()) {
152	                continue;
153	            }
154	            if !call_graph.contains_key(&function) {
155	                continue;
156	            }
157	
158	            propagated
159	                .entry(function.clone())
160	                .and_modify(|current: &mut u64| *current = (*current).max(*alignment))
161	                .or_insert(*alignment);
162	            if let Some(callees) = call_graph.get(&function) {
163	                worklist.extend(callees.iter().cloned());
164	            }
165	        }
166	    }
167	
168	    propagated
169	}
170	
171	fn dynamic_shared_alignment_attr(ctx: &Context, op: Ptr<Operation>) -> Option<u64> {
172	    let key: pliron::identifier::Identifier = DYNAMIC_SHARED_ALIGNMENT_ATTR
173	        .try_into()
174	        .expect("static identifier");
175	    op.deref(ctx)
176	        .attributes
177	        .get::<pliron::builtin::attributes::IntegerAttr>(&key)
178	        .map(|attribute| attribute.value().to_u64())
179	}
180	
181	fn set_dynamic_shared_alignment_attr(ctx: &mut Context, op: Ptr<Operation>, alignment: u64) {
182	    use pliron::builtin::attributes::IntegerAttr;
183	    use pliron::builtin::types::Signedness;
184	    use pliron::utils::apint::APInt;
185	    use std::num::NonZero;
186	
187	    let key: pliron::identifier::Identifier = DYNAMIC_SHARED_ALIGNMENT_ATTR
188	        .try_into()
189	        .expect("static identifier");
190	    let u64_ty = pliron::builtin::types::IntegerType::get(ctx, 64, Signedness::Unsigned);
191	    let value = APInt::from_u64(alignment, NonZero::new(64).unwrap());
192	    op.deref_mut(ctx)
193	        .attributes
194	        .set(key, IntegerAttr::new(u64_ty, value));
195	}
196	
197	// ============================================================================
198	// Function Conversion
199	// ============================================================================
200	
201	/// Convert a `MirFuncOp` to `llvm.func` using pliron's `inline_region`.
202	///
203	/// Called from `crate::MirToLlvmConversionDriver::rewrite` when the
204	/// framework encounters a `MirFuncOp`. Creates a new LLVM function,
205	/// propagates kernel attributes, moves the MIR body via `inline_region`,
206	/// and builds an entry prologue to reconstruct aggregate arguments.
207	#[allow(clippy::too_many_arguments)]
208	pub fn convert_func(
209	    ctx: &mut Context,
210	    rewriter: &mut DialectConversionRewriter,
211	    op: Ptr<Operation>,
212	    _operands_info: &OperandsInfo,
213	    _shared_globals: &mut SharedGlobalsMap,
214	    dynamic_smem_alignments: &mut DynamicSmemAlignmentMap,
215	) -> Result<()> {
216	    let mir_func = MirFuncOp::wrap(ctx, op).expect("expected MirFuncOp");
217	    let name = mir_func.get_symbol_name(ctx);
218	    let func_name_str = name.to_string();
219	
220	    let kernel_key: pliron::identifier::Identifier = "gpu_kernel".try_into().unwrap();
221	    let is_kernel = is_kernel_func(ctx, op);
222	
223	    let func_type = mir_func.get_type(ctx);
224	
225	    // Kernel parameters are host data: the host writes them (by value at
226	    // launch, or into DeviceBuffer memory behind a pointer or slice) and
227	    // the kernel reads the same bytes, so both sides must agree on what
228	    // every byte means. Most enums are fine; their device layout is
229	    // byte-identical to rustc's. The exception is enums whose layout we
230	    // do not model: niche-encoded ones like Option<&T>, where the host
231	    // stores NO tag at all (it marks None with an impossible payload
232	    // value, null, since a real &T is never null) while the device adds
233	    // an explicit tag of its own. The two sides would read different
234	    // bytes, so reject those here at the boundary. Using such an enum
235	    // purely inside a kernel is fine and stays allowed.
236	    if is_kernel {
237	        let mir_arg_types = {
238	            use pliron::builtin::type_interfaces::FunctionTypeInterface;
239	            let ft_ref = func_type.deref(ctx);
240	            ft_ref.arg_types().to_vec()
241	        };
242	        for (i, arg_ty) in mir_arg_types.iter().enumerate() {
243	            let mut visited = Vec::new();
244	            if let Some(enum_name) =
245	                crate::convert::types::find_unmodeled_enum_in_abi(ctx, *arg_ty, &mut visited)
246	                    .map_err(anyhow_to_pliron)?
247	            {
248	                return pliron::input_err_noloc!(
249	                    "kernel `{}` parameter {} contains enum `{}`, whose layout differs \
250	                     between host and device: the host encodes the variant inside the \
251	                     payload itself (Rust's niche optimisation, e.g. null means None for \
252	                     a never-null reference) while the device stores an explicit tag. \
253	                     Reading it from a kernel would read the wrong bytes. Give the enum an \
254	                     explicit discriminant repr (e.g. #[repr(u32)]) to pass it across the \
255	                     kernel boundary; using `{}` only inside kernel code (locals, \
256	                     construct, match) works as before.",
257	                    func_name_str,
258	                    i,
259	                    enum_name,
260	                    enum_name
261	                );
262	            }
263	        }
264	    }
265	    let llvm_func_type =
266	        convert_function_type(ctx, func_type, is_kernel).map_err(anyhow_to_pliron)?;
267	
268	    let llvm_func = llvm::FuncOp::new(ctx, name, llvm_func_type);
269	    llvm::copy_debug_source_scope_map(ctx, op, llvm_func.get_operation());
270	
271	    if is_kernel {
272	        propagate_kernel_attrs(ctx, op, &llvm_func, &kernel_key);
273	    }
274	
275	    propagate_alwaysinline_attr(ctx, op, &llvm_func);
276	
277	    let llvm_entry = llvm_func.get_or_create_entry_block(ctx);
278	
279	    let mir_region = op.deref(ctx).get_region(0);
280	    let mir_entry = mir_region.deref(ctx).get_head();
281	
282	    if let Some(mir_entry) = mir_entry {
283	        // Pre-scan MIR blocks for max dynamic shared memory alignment.
284	        // Must happen BEFORE inline_region empties the MIR region.
285	        let mir_blocks: Vec<_> = mir_region.deref(ctx).iter(ctx).collect();
286	        let body_max_align = compute_max_dynamic_smem_alignment(ctx, &mir_blocks);
287	        let contract_min_align = dynamic_shared_alignment_attr(ctx, op);
288	        let max_align = match (body_max_align, contract_min_align) {
289	            (Some(body), Some(contract)) => Some(body.max(contract)),
290	            (body, contract) => body.or(contract),
291	        };
292	
293	        // Stamp ABI alignment onto load/store/alloca/ref ops while types are
294	        // still MIR — repr(align(N)) is visible on MirStructType but lost after
295	        // type conversion (LLVM struct types carry no over-alignment).
296	        stamp_memory_op_alignment(ctx, &mir_blocks);
297	
298	        if let Some(align) = max_align {
299	            let symbol_name: pliron::identifier::Identifier =
300	                format!("__dynamic_smem_{}", func_name_str)
301	                    .as_str()
302	                    .try_into()
303	                    .expect("Invalid function name for symbol");
304	            dynamic_smem_alignments.insert(func_name_str, (symbol_name, align));
305	        }
306	
307	        // Extract MIR arg types for entry prologue reconstruction
308	        let mir_arg_types = {
309	            use pliron::builtin::type_interfaces::FunctionTypeInterface;
310	            let ft_ref = func_type.deref(ctx);
311	            ft_ref.arg_types().to_vec()
312	        };
313	
314	        let reconstructed_args = build_entry_prologue(ctx, &mir_arg_types, llvm_entry, is_kernel)
315	            .map_err(anyhow_to_pliron)?;
316	
317	        rewriter.inline_region(ctx, mir_region, BlockInsertionPoint::AfterBlock(llvm_entry));
318	
319	        // Insert BrOp through the rewriter so the framework sees it as a
320	        // terminator and converts the MIR entry block's argument types.
321	        let saved_ip = rewriter.get_insertion_point();
322	        rewriter.set_insertion_point(OpInsertionPoint::AtBlockEnd(llvm_entry));
323	        let br = llvm::BrOp::new(ctx, mir_entry, reconstructed_args);
324	        rewriter.insert_operation(ctx, br.get_operation());
325	        rewriter.set_insertion_point(saved_ip);
326	    }
327	
328	    rewriter.insert_operation(ctx, llvm_func.get_operation());
329	    rewriter.replace_operation(ctx, op, llvm_func.get_operation());
330	    Ok(())
331	}
