333	// ============================================================================
334	// Kernel Attribute Propagation
335	// ============================================================================
336	
337	/// Propagate GPU kernel attributes from MIR func to LLVM func.
338	fn propagate_kernel_attrs(
339	    ctx: &mut Context,
340	    mir_op: Ptr<Operation>,
341	    llvm_func: &llvm::FuncOp,
342	    kernel_key: &pliron::identifier::Identifier,
343	) {
344	    llvm_func.get_operation().deref_mut(ctx).attributes.set(
345	        kernel_key.clone(),
346	        pliron::builtin::attributes::StringAttr::new("true".to_string()),
347	    );
348	
349	    // Extract MIR attrs first to avoid borrow overlap with deref_mut below
350	    let attrs_to_copy: Vec<_> = {
351	        let mir_attrs = &mir_op.deref(ctx).attributes;
352	        [
353	            "cluster_dim_x",
354	            "cluster_dim_y",
355	            "cluster_dim_z",
356	            "maxntid",
357	            "minctasm",
358	        ]
359	        .iter()
360	        .filter_map(|key_str| {
361	            let key: pliron::identifier::Identifier = (*key_str).try_into().unwrap();
362	            mir_attrs
363	                .get::<pliron::builtin::attributes::IntegerAttr>(&key)
364	                .map(|attr| (key, attr.clone()))
365	        })
366	        .collect()
367	    };
368	
369	    for (key, attr) in attrs_to_copy {
370	        llvm_func
371	            .get_operation()
372	            .deref_mut(ctx)
373	            .attributes
374	            .set(key, attr);
375	    }
376	}
377	
378	/// Propagate the `alwaysinline` attribute from MIR func to LLVM func.
379	///
380	/// Set on the MIR func op by `mir-importer` when the source Rust function
381	/// carries `#[inline(always)]`. The LLVM exporter then emits the
382	/// `alwaysinline` keyword on the `define` line. Existing `opt -O2` runs can
383	/// honor that attribute before `llc`, but this propagation is not a mandatory
384	/// always-inline pass. The goal is to preserve Rust's inline intent for device
385	/// helpers rather than leaving helper boundaries solely to optimizer
386	/// heuristics.
387	fn propagate_alwaysinline_attr(
388	    ctx: &mut Context,
389	    mir_op: Ptr<Operation>,
390	    llvm_func: &llvm::FuncOp,
391	) {
392	    let key: pliron::identifier::Identifier = "alwaysinline".try_into().unwrap();
393	    let attr_opt = mir_op
394	        .deref(ctx)
395	        .attributes
396	        .get::<pliron::builtin::attributes::StringAttr>(&key)
397	        .cloned();
398	    if let Some(attr) = attr_opt {
399	        llvm_func
400	            .get_operation()
401	            .deref_mut(ctx)
402	            .attributes
403	            .set(key, attr);
404	    }
405	}
