407	// ============================================================================
408	// Entry Block Prologue
409	// ============================================================================
410	
411	/// Build LLVM entry block prologue: reconstruct aggregate args from flattened
412	/// LLVM block arguments and return the values to pass to the MIR entry block.
413	///
414	/// The LLVM entry block args reflect the post-flatten function signature.
415	/// Slices always arrive as `(ptr, len)` pairs and get re-assembled via
416	/// `insertvalue`. Structs only arrive flattened on the internal device-fn
417	/// ABI; at kernel boundaries (`is_kernel_entry = true`) they arrive as a
418	/// single byval value and pass through. This function decides the shape
419	/// per-argument and emits the matching reconstruction sequence.
420	fn build_entry_prologue(
421	    ctx: &mut Context,
422	    mir_arg_types: &[TypeHandle],
423	    llvm_entry: Ptr<BasicBlock>,
424	    is_kernel_entry: bool,
425	) -> std::result::Result<Vec<Value>, anyhow::Error> {
426	    let llvm_args: Vec<_> = llvm_entry.deref(ctx).arguments().collect();
427	    let mut llvm_arg_idx = 0;
428	    let mut last_op: Option<Ptr<Operation>> = None;
429	    let mut result_args = Vec::new();
430	
431	    for &mir_ty in mir_arg_types {
432	        let kind = classify_argument_type(ctx, mir_ty, is_kernel_entry);
433	
434	        match kind {
435	            ReconstructKind::Slice => {
436	                if llvm_arg_idx + 1 >= llvm_args.len() {
437	                    return Err(anyhow::anyhow!(
438	                        "Entry block arg mismatch: need 2 more LLVM args for slice"
439	                    ));
440	                }
441	                let ptr_val = llvm_args[llvm_arg_idx];
442	                let len_val = llvm_args[llvm_arg_idx + 1];
443	                llvm_arg_idx += 2;
444	
445	                let (val, new_last) =
446	                    reconstruct_slice(ctx, llvm_entry, last_op, mir_ty, ptr_val, len_val)?;
447	                last_op = Some(new_last);
448	                result_args.push(val);
449	            }
450	            ReconstructKind::Struct(num_fields) => {
451	                if llvm_arg_idx + num_fields > llvm_args.len() {
452	                    return Err(anyhow::anyhow!(
453	                        "Entry block arg mismatch: need {} more LLVM args for struct",
454	                        num_fields
455	                    ));
456	                }
457	                let field_vals: Vec<Value> = (0..num_fields)
458	                    .map(|i| llvm_args[llvm_arg_idx + i])
459	                    .collect();
460	                llvm_arg_idx += num_fields;
461	
462	                let (val, new_last) =
463	                    reconstruct_struct(ctx, llvm_entry, last_op, mir_ty, &field_vals)?;
464	                last_op = Some(new_last);
465	                result_args.push(val);
466	            }
467	            ReconstructKind::Zst => {
468	                let llvm_ty = convert_type(ctx, mir_ty)?;
469	                let undef = llvm::UndefOp::new(ctx, llvm_ty).get_operation();
470	                insert_op_sequentially(undef, llvm_entry, last_op, ctx);
471	                last_op = Some(undef);
472	                result_args.push(undef.deref(ctx).get_result(0));
473	            }
474	            ReconstructKind::None => {
475	                if llvm_arg_idx >= llvm_args.len() {
476	                    return Err(anyhow::anyhow!(
477	                        "Entry block arg mismatch: no more LLVM args available"
478	                    ));
479	                }
480	                result_args.push(llvm_args[llvm_arg_idx]);
481	                llvm_arg_idx += 1;
482	            }
483	        }
484	    }
485	
486	    Ok(result_args)
487	}
488	
489	// ============================================================================
490	// Argument Classification
491	// ============================================================================
492	
493	/// Classification of argument types for reconstruction strategy.
494	enum ReconstructKind {
495	    /// A slice type (`&[T]` or `DisjointSlice<T>`), flattened to `(ptr, len)`.
496	    Slice,
497	    /// A struct type with N non-ZST fields, flattened to N separate arguments.
498	    Struct(usize),
499	    /// A zero-sized argument omitted from the LLVM signature.
500	    Zst,
501	    /// A simple type that passes through without reconstruction.
502	    None,
503	}
504	
505	/// Classify an argument type to determine how to reconstruct it from
506	/// flattened LLVM entry block arguments.
507	///
508	/// At kernel-entry boundaries (`is_kernel_entry = true`) structs arrive
509	/// intact, so they're classified as `None` even though the MIR type is
510	/// `MirStructType`. Slices keep their `(ptr, len)` reconstruction on
511	/// both ABIs.
512	fn classify_argument_type(
513	    ctx: &mut Context,
514	    arg_ty: TypeHandle,
515	    is_kernel_entry: bool,
516	) -> ReconstructKind {
517	    if convert_type(ctx, arg_ty).is_ok_and(|llvm_ty| is_zero_sized_type(ctx, llvm_ty)) {
518	        return ReconstructKind::Zst;
519	    }
520	
521	    let (is_slice, struct_fields) = {
522	        let arg_ty_ref = arg_ty.deref(ctx);
523	        let is_slice = arg_ty_ref.is::<MirSliceType>() || arg_ty_ref.is::<MirDisjointSliceType>();
524	        let struct_fields = arg_ty_ref
525	            .downcast_ref::<MirStructType>()
526	            .map(|s| s.field_types.clone());
527	        (is_slice, struct_fields)
528	    };
529	
530	    if is_slice {
531	        ReconstructKind::Slice
532	    } else if let Some(fields) = struct_fields {
533	        // Count non-ZST fields the same way `convert_function_type` does
534	        // — empty structs and structs of all-ZSTs are themselves ZST and
535	        // get dropped from the LLVM signature on both ABIs.
536	        let non_zst_count = fields
537	            .iter()
538	            .filter(|f| {
539	                convert_type(ctx, **f)
540	                    .map(|llvm_ty| !is_zero_sized_type(ctx, llvm_ty))
541	                    .unwrap_or(true)
542	            })
543	            .count();
544	
545	        if non_zst_count == 0 {
546	            ReconstructKind::Zst
547	        } else if is_kernel_entry {
548	            // Kernel boundary: struct arrived as a single byval value,
549	            // so the MIR entry block can consume it directly without
550	            // any insertvalue prologue.
551	            ReconstructKind::None
552	        } else {
553	            ReconstructKind::Struct(non_zst_count)
554	        }
555	    } else {
556	        ReconstructKind::None
557	    }
558	}
559	
560	// ============================================================================
561	// Aggregate Reconstruction
562	// ============================================================================
563	
564	/// Reconstruct a slice value from flattened pointer and length.
565	///
566	/// Generates: `undef → insertvalue ptr[0] → insertvalue len[1]`.
567	/// Returns the final reconstructed value and the last inserted operation.
568	fn reconstruct_slice(
569	    ctx: &mut Context,
570	    llvm_block: Ptr<BasicBlock>,
571	    prev_op: Option<Ptr<Operation>>,
572	    mir_ty: TypeHandle,
573	    ptr_val: Value,
574	    len_val: Value,
575	) -> std::result::Result<(Value, Ptr<Operation>), anyhow::Error> {
576	    let struct_ty = convert_type(ctx, mir_ty)?;
577	
578	    let undef = llvm::UndefOp::new(ctx, struct_ty);
579	    let undef_op = undef.get_operation();
580	    insert_op_sequentially(undef_op, llvm_block, prev_op, ctx);
581	    let undef_val = undef_op.deref(ctx).get_result(0);
582	
583	    let insert_ptr = llvm::InsertValueOp::new(ctx, undef_val, ptr_val, vec![0]);
584	    let insert_ptr_op = insert_ptr.get_operation();
585	    insert_ptr_op.insert_after(ctx, undef_op);
586	    let val_with_ptr = insert_ptr_op.deref(ctx).get_result(0);
587	
588	    let insert_len = llvm::InsertValueOp::new(ctx, val_with_ptr, len_val, vec![1]);
589	    let insert_len_op = insert_len.get_operation();
590	    insert_len_op.insert_after(ctx, insert_ptr_op);
591	    let final_val = insert_len_op.deref(ctx).get_result(0);
592	
593	    Ok((final_val, insert_len_op))
594	}
595	
596	/// Reconstruct a struct value from flattened field values.
597	///
598	/// `field_vals` carries the flattened args in memory order with ZST fields
599	/// skipped (the same walk `convert_function_type` for the callee signature
600	/// and `flatten_arguments` at call sites use). Each value is inserted at the LLVM
601	/// slot [`build_struct_slot_map`] assigned to its field, so reconstruction
602	/// skips `[N x i8]` padding slots instead of inserting into them
603	/// (issue #128).
604	///
605	/// Generates: `undef → insertvalue field[slot] → ...`.
606	/// Returns the final reconstructed value and the last inserted operation.
607	fn reconstruct_struct(
608	    ctx: &mut Context,
609	    llvm_block: Ptr<BasicBlock>,
610	    prev_op: Option<Ptr<Operation>>,
611	    mir_ty: TypeHandle,
612	    field_vals: &[Value],
613	) -> std::result::Result<(Value, Ptr<Operation>), anyhow::Error> {
614	    let layout = {
615	        let ty_ref = mir_ty.deref(ctx);
616	        match ty_ref.downcast_ref::<MirStructType>() {
617	            Some(s) => StructLayoutInfo::of_struct(s),
618	            None => {
619	                return Err(anyhow::anyhow!(
620	                    "reconstruct_struct: expected a MirStructType argument"
621	                ));
622	            }
623	        }
624	    };
625	    let map = build_struct_slot_map(ctx, &layout)?;
626	
627	    let undef = llvm::UndefOp::new(ctx, map.llvm_struct_ty);
628	    let undef_op = undef.get_operation();
629	    insert_op_sequentially(undef_op, llvm_block, prev_op, ctx);
630	    let mut current_struct = undef_op.deref(ctx).get_result(0);
631	    let mut last_op = undef_op;
632	
633	    let mut vals = field_vals.iter();
634	    for &decl_idx in &layout.mem_to_decl {
635	        let Some(slot) = map.decl_to_llvm[decl_idx] else {
636	            continue; // ZST field: never flattened into an arg.
637	        };
638	        let Some(field_val) = vals.next() else {
639	            return Err(anyhow::anyhow!(
640	                "reconstruct_struct: fewer flattened args than non-ZST struct fields"
641	            ));
642	        };
643	        let insert_field = llvm::InsertValueOp::new(ctx, current_struct, *field_val, vec![slot]);
644	        let insert_op = insert_field.get_operation();
645	        insert_op.insert_after(ctx, last_op);
646	        current_struct = insert_op.deref(ctx).get_result(0);
647	        last_op = insert_op;
648	    }
649	    if vals.next().is_some() {
650	        return Err(anyhow::anyhow!(
651	            "reconstruct_struct: more flattened args than non-ZST struct fields"
652	        ));
653	    }
654	
655	    Ok((current_struct, last_op))
656	}
657	
658	/// Insert an op sequentially: after `prev` if given, otherwise at block front.
659	fn insert_op_sequentially(
660	    op: Ptr<Operation>,
661	    block: Ptr<BasicBlock>,
662	    prev: Option<Ptr<Operation>>,
663	    ctx: &Context,
664	) {
665	    if let Some(prev_op) = prev {
666	        op.insert_after(ctx, prev_op);
667	    } else {
668	        op.insert_at_front(block, ctx);
669	    }
670	}
