672	// ============================================================================
673	// Dynamic Shared Memory Pre-scan
674	// ============================================================================
675	
676	/// Compute the maximum dynamic shared memory alignment across all
677	/// `MirExternSharedOp` operations in a function.
678	///
679	/// This pre-pass must run BEFORE `inline_region` moves the blocks, since
680	/// it iterates the MIR blocks directly. The result is stored in
681	/// [`DynamicSmemAlignmentMap`] so that later per-op converters can
682	/// create the global with the correct alignment.
683	fn compute_max_dynamic_smem_alignment(
684	    ctx: &Context,
685	    mir_blocks: &[Ptr<BasicBlock>],
686	) -> Option<u64> {
687	    let mut max_alignment: Option<u64> = None;
688	
689	    for mir_block in mir_blocks {
690	        for op in mir_block.deref(ctx).iter(ctx) {
691	            let op_id = Operation::get_opid(op, ctx);
692	            if op_id == dialect_mir::ops::MirExternSharedOp::get_opid_static() {
693	                let extern_shared = dialect_mir::ops::MirExternSharedOp::new(op);
694	                let alignment = extern_shared.get_alignment_value(ctx);
695	
696	                max_alignment = Some(match max_alignment {
697	                    Some(current_max) => current_max.max(alignment),
698	                    None => alignment,
699	                });
700	            }
701	        }
702	    }
703	
704	    max_alignment
705	}
