707	// ============================================================================
708	// Error Conversion
709	// ============================================================================
710	
711	/// Convert an `anyhow::Error` into a `pliron::result::Error`.
712	fn anyhow_to_pliron(e: anyhow::Error) -> pliron::result::Error {
713	    pliron::create_error!(
714	        pliron::location::Location::Unknown,
715	        pliron::result::ErrorKind::VerificationFailed,
716	        pliron::result::StringError(e.to_string())
717	    )
718	}
719	
720	// ============================================================================
721	// Alignment Pre-Pass
722	// ============================================================================
723	
724	/// The real (rustc) alignment of a struct or enum type, when recorded.
725	///
726	/// The converted LLVM struct alone can claim too little: an enum that
727	/// lowers to `{ i8, [7 x i8] }` looks like "align 1" to LLVM even when
728	/// Rust requires align 8. Memory ops touching such values get stamped
729	/// with the recorded alignment instead.
730	fn aggregate_over_align(ctx: &Context, ty: TypeHandle) -> Option<u64> {
731	    let ty_ref = ty.deref(ctx);
732	    if let Some(s) = ty_ref.downcast_ref::<MirStructType>() {
733	        return Some(s.abi_align).filter(|a| *a > 0);
734	    }
735	    if let Some(e) = ty_ref.downcast_ref::<dialect_mir::types::MirEnumType>() {
736	        return Some(e.abi_align()).filter(|a| *a > 0);
737	    }
738	    if let Some(u) = ty_ref.downcast_ref::<MirUnionType>() {
739	        return Some(u.abi_align()).filter(|a| *a > 0);
740	    }
741	    None
742	}
743	
744	/// Stamp the true ABI alignment onto every `mir.load`, `mir.store`,
745	/// `mir.alloca`, and `mir.ref` whose accessed/allocated type carries a
746	/// rustc ABI alignment in `MirStructType`, `MirEnumType`, or `MirUnionType`.
747	///
748	/// Must run BEFORE `inline_region` moves the blocks and BEFORE dialect
749	/// conversion replaces MIR types with LLVM types, since the alignment
750	/// information lives on the MIR types and is not expressible on LLVM
751	/// struct types.
752	fn stamp_memory_op_alignment(ctx: &mut Context, mir_blocks: &[Ptr<BasicBlock>]) {
753	    let load_id = dialect_mir::ops::MirLoadOp::get_opid_static();
754	    let store_id = dialect_mir::ops::MirStoreOp::get_opid_static();
755	    let alloca_id = dialect_mir::ops::MirAllocaOp::get_opid_static();
756	    let ref_id = dialect_mir::ops::MirRefOp::get_opid_static();
757	
758	    // Collect (op, align) first (read-only pass), then stamp (write pass).
759	    let mut to_stamp: Vec<(Ptr<Operation>, u64)> = Vec::new();
760	    for mir_block in mir_blocks {
761	        let ops: Vec<_> = mir_block.deref(ctx).iter(ctx).collect();
762	        for op in ops {
763	            let op_id = Operation::get_opid(op, ctx);
764	            let align = if op_id == load_id {
765	                // load: result(0) is the loaded value.
766	                aggregate_over_align(ctx, op.deref(ctx).get_result(0).get_type(ctx))
767	            } else if op_id == store_id {
768	                // store: operand(1) is the stored value.
769	                aggregate_over_align(ctx, op.deref(ctx).get_operand(1).get_type(ctx))
770	            } else if op_id == alloca_id {
771	                // alloca: pointee type lives inside the MirPtrType result.
772	                let res_ty = op.deref(ctx).get_result(0).get_type(ctx);
773	                res_ty
774	                    .deref(ctx)
775	                    .downcast_ref::<MirPtrType>()
776	                    .map(|p| p.pointee)
777	                    .and_then(|pointee| aggregate_over_align(ctx, pointee))
778	            } else if op_id == ref_id {
779	                // ref: operand(0) is the value being referenced (spilled to
780	                // stack). If it is an over-aligned struct, the synthesised
781	                // alloca+store in convert_ref must honour that alignment.
782	                aggregate_over_align(ctx, op.deref(ctx).get_operand(0).get_type(ctx))
783	            } else {
784	                None
785	            };
786	            if let Some(a) = align {
787	                to_stamp.push((op, a));
788	            }
789	        }
790	    }
791	
792	    for (op, align) in to_stamp {
793	        llvm_export::ops::set_op_alignment(ctx, op, align as u32);
794	    }
795	}
796	
797	// ============================================================================
798	// Pass Registration
799	// ============================================================================
800	
801	/// Register the MIR → LLVM lowering pass (placeholder for pass infrastructure).
802	pub fn register(_ctx: &mut Context) {}
803	
804	#[cfg(test)]
805	mod dynamic_shared_contract_tests {
806	    use super::*;
807	
808	    fn graph(entries: &[(&str, &[&str])]) -> FxHashMap<String, Vec<String>> {
809	        entries
810	            .iter()
811	            .map(|(caller, callees)| {
812	                (
813	                    (*caller).to_string(),
814	                    callees.iter().map(|callee| (*callee).to_string()).collect(),
815	                )
816	            })
817	            .collect()
818	    }
819	
820	    #[test]
821	    fn propagation_is_transitive_cycle_safe_and_takes_shared_helper_maximum() {
822	        let call_graph = graph(&[
823	            ("kernel_32", &["forward", "external"]),
824	            ("kernel_256", &["shared"]),
825	            ("kernel_64", &["cycle_a"]),
826	            ("forward", &["shared"]),
827	            ("shared", &[]),
828	            ("cycle_a", &["cycle_b"]),
829	            ("cycle_b", &["cycle_a"]),
830	            ("marked_helper", &["marked_owner"]),
831	            ("marked_owner", &[]),
832	            ("uncontracted", &["unreached_helper"]),
833	            ("unreached_helper", &[]),
834	        ]);
835	        let contracts = [
836	            ("kernel_32".to_string(), 32),
837	            ("kernel_256".to_string(), 256),
838	            ("kernel_64".to_string(), 64),
839	            ("marked_helper".to_string(), 128),
840	        ];
841	
842	        let propagated = propagate_alignments_through_call_graph(&call_graph, &contracts);
843	
844	        assert_eq!(propagated.get("forward"), Some(&32));
845	        assert_eq!(propagated.get("shared"), Some(&256));
846	        assert_eq!(propagated.get("cycle_a"), Some(&64));
847	        assert_eq!(propagated.get("cycle_b"), Some(&64));
848	        assert_eq!(propagated.get("marked_owner"), Some(&128));
849	        assert!(!propagated.contains_key("external"));
850	        assert!(!propagated.contains_key("uncontracted"));
851	        assert!(!propagated.contains_key("unreached_helper"));
852	    }
853	}
