333	            artifact_kind: ModuleArtifactKind::NvvmIr,
334	            target: nvvm_target
335	                .expect("NVVM target was resolved before export")
336	                .sm(),
337	            diagnostics: Vec::new(),
338	        });
339	    }
340	
341	    if request.trace.verbose {
342	        request.trace.emit("\n=== Generating PTX ===");
343	    }
344	    let generated = match request.toolchain {
345	        ToolchainPolicy::Discover => generate_ptx(
346	            request.files.llvm_ir,
347	            request.files.ptx,
348	            request.debug_kind,
349	            request.backend,
350	            request.trace.sink,
351	        )?,
352	        ToolchainPolicy::Explicit(toolchain) => GeneratedPtx {
353	            target: generate_ptx_with_toolchain(
354	                request.files.llvm_ir,
355	                request.files.ptx,
356	                request.debug_kind,
357	                request.backend,
358	                toolchain,
359	            )?,
360	            diagnostics: Vec::new(),
361	        },
362	    };
363	    if request.trace.verbose {
364	        request.trace.emit(format!(
365	            "✓ PTX written to {} (target: {})",
366	            request.files.ptx.display(),
367	            generated.target
368	        ));
369	    }
370	    Ok(ModulePipelineOutput {
371	        artifact_kind: ModuleArtifactKind::Ptx,
372	        target: generated.target,
373	        diagnostics: generated.diagnostics,
374	    })
375	}
376	
377	fn should_emit_nvvm_ir(policy: OutputPolicy, needs_libdevice: bool) -> bool {
378	    match policy {
379	        OutputPolicy::SelfContainedPtx => false,
380	        OutputPolicy::ExternalLinkAllowed { request_nvvm_ir } => request_nvvm_ir || needs_libdevice,
381	    }
382	}
383	
384	fn as_lowered_verification(error: PipelineError) -> PipelineError {
385	    match error {
386	        PipelineError::Verification {
387	            message, operation, ..
388	        } => PipelineError::LoweredVerification { message, operation },
389	        other => other,
390	    }
391	}
