5	
6	//! Arithmetic operation conversion: `dialect-mir` → LLVM dialect.
7	//!
8	//! Converts `dialect-mir` arithmetic, bitwise, and comparison operations to
9	//! their LLVM dialect equivalents.
10	//!
11	//! # Operations
12	//!
13	//! | Category      | MIR Operations                    | LLVM Operations                              |
14	//! |---------------|-----------------------------------|----------------------------------------------|
15	//! | Integer Arith | `add`, `sub`, `mul`, `div`, `rem` | `add`, `sub`, `mul`, `sdiv`/`udiv`, `srem`/`urem` |
16	//! | Float Arith   | `add`, `sub`, `mul`, `div`, `rem` | `fadd`, `fsub`, `fmul`, `fdiv`, `frem`       |
17	//! | Unary         | `neg`, `not`                      | `fneg` / `sub 0, x`, `xor`                   |
18	//! | Bitwise       | `and`, `or`, `xor`, `not`         | `and`, `or`, `xor`                           |
19	//! | Shifts        | `shl`, `shr`                      | `shl`, `lshr`/`ashr`                         |
20	//! | Comparison    | `lt`, `le`, `gt`, `ge`, `eq`, `ne`| `icmp` (signed/unsigned predicates), `fcmp`   |
21	//! | Checked       | `checked_add`                     | `add` + overflow tuple                       |
22	//!
23	//! # Type Handling
24	//!
25	//! - Integer operations use signless LLVM types
26	//! - Float operations automatically use `fadd`, `fmul`, etc. with fastmath flags
27	//! - Shift amounts are cast and masked to match Rust's unchecked shift semantics
28	//! - Checked operations return `(result, overflow_flag)` tuples
29	
30	use crate::convert::intrinsics::common::call_intrinsic;
31	use crate::convert::types::convert_type;
32	use llvm_export::attributes::{
33	    FCmpPredicateAttr, FastmathFlags, FastmathFlagsAttr, ICmpPredicateAttr,
34	    IntegerOverflowFlagsAttr,
35	};
36	use llvm_export::op_interfaces::{BinArithOp, CastOpInterface, IntBinArithOpWithOverflowFlag};
37	use llvm_export::ops as llvm;
38	use llvm_export::types as llvm_types;
39	use pliron::builtin::attributes::IntegerAttr;
40	use pliron::builtin::types::{FP32Type, FP64Type, IntegerType, Signedness};
41	use pliron::context::{Context, Ptr};
42	use pliron::irbuild::dialect_conversion::{DialectConversionRewriter, OperandsInfo};
43	use pliron::irbuild::inserter::Inserter;
44	use pliron::irbuild::rewriter::Rewriter;
45	use pliron::location::Located;
46	use pliron::op::Op;
47	use pliron::operation::Operation;
48	use pliron::result::Result;
49	use pliron::r#type::Typed;
50	use pliron::value::Value;
51	
52	// ============================================================================
53	// Helper functions for binary operations
54	// ============================================================================
55	
56	/// Extract binary operands from the (already-converted) operation.
57	fn get_binary_operands(op: Ptr<Operation>, ctx: &Context) -> Result<(Value, Value)> {
58	    let loc = op.deref(ctx).loc();
59	    let operands: Vec<_> = op.deref(ctx).operands().collect();
60	    match operands.as_slice() {
61	        [lhs, rhs] => Ok((*lhs, *rhs)),
62	        _ => pliron::input_err!(loc, "Binary operation requires exactly 2 operands"),
63	    }
64	}
65	
66	/// Check if a value has floating-point type.
67	fn is_float_type(ctx: &Context, val: Value) -> bool {
68	    let ty = val.get_type(ctx);
69	    ty.deref(ctx).is::<llvm_export::types::HalfType>()
70	        || ty.deref(ctx).is::<FP32Type>()
71	        || ty.deref(ctx).is::<FP64Type>()
72	}
