74	/// Check if a binary operation's integer operands were signed before type conversion.
75	///
76	/// Uses `operands_info` to read the *pre-conversion* MIR type (which preserves
77	/// Rust's signedness). After DialectConversion, the live operand type is already
78	/// signless. Pointer types are treated as unsigned. Operands with no conversion
79	/// history (types that were never convertible, today only signless i1 bools)
80	/// fall back to the live type's signedness.
81	fn is_signed_int_op(
82	    ctx: &Context,
83	    op: Ptr<Operation>,
84	    operands_info: &OperandsInfo,
85	) -> Result<bool> {
86	    let operand = op.deref(ctx).get_operand(0);
87	    if let Some(int_ty) = operands_info.lookup_most_recent_of_type::<IntegerType>(ctx, operand) {
88	        Ok(int_ty.signedness() == Signedness::Signed)
89	    } else if operands_info
90	        .lookup_most_recent_of_type::<dialect_mir::types::MirPtrType>(ctx, operand)
91	        .is_some()
92	    {
93	        Ok(false)
94	    } else {
95	        // No conversion history exists for this operand: its type was never
96	        // convertible, so DialectConversion recorded nothing for it. Today
97	        // that is only signless i1 bools (e.g. a phi produced by
98	        // short-circuit `||`/`&&`). Fall back to the live operand type and
99	        // honor its signedness: signless lowers as unsigned, and pointers
100	        // are always unsigned.
101	        let live = operand.get_type(ctx);
102	        let live_ref = live.deref(ctx);
103	        if let Some(int_ty) = live_ref.downcast_ref::<IntegerType>() {
104	            Ok(int_ty.signedness() == Signedness::Signed)
105	        } else if live_ref.is::<dialect_mir::types::MirPtrType>() {
106	            Ok(false)
107	        } else {
108	            pliron::input_err!(
109	                op.deref(ctx).loc(),
110	                "expected IntegerType or MirPtrType operand in arithmetic op"
111	            )
112	        }
113	    }
114	}
