116	/// Add the configured fast-math flags to a floating-point operation.
117	///
118	/// By default this sets ONLY `contract`, which lets the NVPTX backend fuse an
119	/// `fmul` feeding an `fadd`/`fsub` into a single `fma.rn.f32`. This matches
120	/// nvcc's default `--fmad=true`: the one fast-math relaxation NVIDIA enables
121	/// out of the box. When the caller disables contraction, no fast-math
122	/// permission is granted and multiply/add operations round separately.
123	///
124	/// We deliberately never set reassoc/nnan/ninf/nsz/arcp, so results stay
125	/// bit-comparable to the selected contracted or uncontracted reference.
126	fn add_fastmath_flags(ctx: &mut Context, op: Ptr<Operation>) {
127	    let flags = if crate::context::lowering_options(ctx).allow_fma_contraction {
128	        FastmathFlags::CONTRACT
129	    } else {
130	        FastmathFlags::empty()
131	    };
132	    let flags = FastmathFlagsAttr(flags);
133	    let key: pliron::identifier::Identifier = "llvm_fast_math_flags".try_into().unwrap();
134	    op.deref_mut(ctx).attributes.set(key, flags);
135	}
