141	/// Convert `mir.add` to `llvm.add` (integer) or `llvm.fadd` (float).
142	///
143	/// Integer additions use default overflow flags (no wrapping behavior).
144	/// Float additions include fastmath flags for potential optimizations.
145	pub(crate) fn convert_add(
146	    ctx: &mut Context,
147	    rewriter: &mut DialectConversionRewriter,
148	    op: Ptr<Operation>,
149	    _operands_info: &OperandsInfo,
150	) -> Result<()> {
151	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
152	
153	    let llvm_op = if is_float_type(ctx, lhs) {
154	        let fadd = llvm::FAddOp::new(ctx, lhs, rhs);
155	        add_fastmath_flags(ctx, fadd.get_operation());
156	        fadd.get_operation()
157	    } else {
158	        let flags = IntegerOverflowFlagsAttr::default();
159	        llvm::AddOp::new_with_overflow_flag(ctx, lhs, rhs, flags).get_operation()
160	    };
161	
162	    rewriter.insert_operation(ctx, llvm_op);
163	    rewriter.replace_operation(ctx, op, llvm_op);
164	    Ok(())
165	}
