376	/// Convert `mir.shr` to `llvm.ashr` (signed, arithmetic) or `llvm.lshr` (unsigned, logical).
377	///
378	/// Signed types use arithmetic shift right (sign-extending), unsigned types
379	/// use logical shift right (zero-filling). The shift count is cast and masked
380	/// before lowering because LLVM shifts are poison when the count is too large.
381	pub(crate) fn convert_shr(
382	    ctx: &mut Context,
383	    rewriter: &mut DialectConversionRewriter,
384	    op: Ptr<Operation>,
385	    operands_info: &OperandsInfo,
386	) -> Result<()> {
387	    let signed = is_signed_int_op(ctx, op, operands_info)?;
388	    convert_shift(ctx, rewriter, op, |ctx, lhs, rhs| {
389	        if signed {
390	            llvm::AShrOp::new(ctx, lhs, rhs).get_operation()
391	        } else {
392	            llvm::LShrOp::new(ctx, lhs, rhs).get_operation()
393	        }
394	    })
395	}
