554	/// Convert `mir.neg` to `llvm.fneg` for floats or `0 - x` for integers.
555	///
556	/// LLVM has a dedicated floating-point negation op. Integer negation is a
557	/// subtraction from zero, which also matches how LLVM represents integer `neg`.
558	pub(crate) fn convert_neg(
559	    ctx: &mut Context,
560	    rewriter: &mut DialectConversionRewriter,
561	    op: Ptr<Operation>,
562	    _operands_info: &OperandsInfo,
563	) -> Result<()> {
564	    use pliron::utils::apint::APInt;
565	    use std::num::NonZeroUsize;
566	
567	    let operand = op.deref(ctx).get_operand(0);
568	    let operand_ty = operand.get_type(ctx);
569	
570	    let llvm_op = if is_float_type(ctx, operand) {
571	        llvm::FNegOp::new_with_fast_math_flags(ctx, operand, FastmathFlagsAttr::default())
572	            .get_operation()
573	    } else {
574	        let width = operand_ty
575	            .deref(ctx)
576	            .downcast_ref::<IntegerType>()
577	            .ok_or_else(|| {
578	                pliron::input_error!(
579	                    op.deref(ctx).loc(),
580	                    "NEG only supports integer or float types"
581	                )
582	            })?
583	            .width();
584	
585	        let zero_ty = IntegerType::get(ctx, width, Signedness::Signless);
586	        let zero_attr = IntegerAttr::new(
587	            zero_ty,
588	            APInt::from_u128(0, NonZeroUsize::new(width as usize).unwrap()),
589	        );
590	        let zero_op = llvm::ConstantOp::new(ctx, zero_attr.into()).get_operation();
591	        rewriter.insert_operation(ctx, zero_op);
592	        let zero = zero_op.deref(ctx).get_result(0);
593	
594	        let flags = IntegerOverflowFlagsAttr::default();
595	        llvm::SubOp::new_with_overflow_flag(ctx, zero, operand, flags).get_operation()
596	    };
597	
598	    rewriter.insert_operation(ctx, llvm_op);
599	    rewriter.replace_operation(ctx, op, llvm_op);
600	    Ok(())
601	}
